import{_ as e,c as t,A as o,o as n}from"./index-Dt2z4w5Z.js";const i={},s={class:"about-view"};function r(l,a){return n(),t("div",s,[...a[0]||(a[0]=[o('<article class="about-content" data-v-80126aae><h1 data-v-80126aae>About StratumRace</h1><section class="about-section" data-v-80126aae><h2 data-v-80126aae>What We Measure</h2><p data-v-80126aae> StratumRace measures how quickly Bitcoin mining pools broadcast new block templates to their miners after a block is found on the network. When a new Bitcoin block is discovered, every pool must notify its miners to start working on the next block. The speed of this notification directly impacts mining efficiency. </p><p data-v-80126aae> We connect to dozens of mining pools from multiple geographic vantage points and precisely time when each collector receives the pool&#39;s <code data-v-80126aae>mining.notify</code> message via the Stratum protocol. The first pool to deliver a full block template at a given vantage wins that race. All other pools&#39; times are measured as offsets from the winner. </p></section><section class="about-section" data-v-80126aae><h2 data-v-80126aae>Why It Matters</h2><p data-v-80126aae> Block notification speed has real economic consequences for miners. During the delay between a new block being found and a pool&#39;s notification arriving, miners relying on that pool&#39;s Stratum notification continue working on the previous (now stale) block template, wasting electricity and hashrate. </p><p data-v-80126aae> Faster notification reduces avoidable work on stale templates and is one component of overall pool performance, alongside fees, reliability, template construction quality, and payout structure. StratumRace provides transparent, independent measurements to help miners make informed decisions about this factor. </p></section><section class="about-section" data-v-80126aae><h2 data-v-80126aae>How It Works</h2><ul data-v-80126aae><li data-v-80126aae><strong data-v-80126aae>Collectors</strong> - Lightweight measurement nodes deployed in multiple geographic locations connect to each pool&#39;s Stratum endpoint and listen for block template notifications.</li><li data-v-80126aae><strong data-v-80126aae>Race Detection</strong> - When a new block&#39;s <code data-v-80126aae>prevhash</code> appears, a 15-second confirmation window begins. All pools&#39; arrival times are recorded relative to the first notification.</li><li data-v-80126aae><strong data-v-80126aae>Full vs Empty Templates</strong> - Some pools send an empty template immediately (fast but contains no transactions) followed by a full template that includes transactions. A race is won by the first pool that delivers a full template. The &quot;Any Template&quot; view shows the first notification regardless of content, while &quot;Full Template&quot; (the default) only considers templates that include transactions.</li><li data-v-80126aae><strong data-v-80126aae>Statistics</strong> - Median offsets are computed per pool across configurable time windows. Win counts and win percentages show which pools consistently deliver first.</li></ul></section><section class="about-section" data-v-80126aae><h2 data-v-80126aae>Vantage Points</h2><p data-v-80126aae> A vantage point is a measurement location: a collector node deployed in a specific geographic region. Results vary by geography. A pool&#39;s server in Frankfurt will naturally appear faster to our European vantage than our US-based one. </p><p data-v-80126aae> We deploy vantages in multiple locations to provide a balanced global view. The &quot;All Vantages&quot; view pools observations from all available vantage points together, while selecting a specific vantage shows only that location&#39;s measurements. </p></section><section class="about-section" data-v-80126aae><h2 data-v-80126aae>Methodology Notes</h2><ul data-v-80126aae><li data-v-80126aae>Timing resolution is bounded by TCP delivery and event-loop scheduling (~0.1ms). Sub-millisecond differences in any single race should be treated as noise.</li><li data-v-80126aae>Pool connections use throwaway Bitcoin addresses. No real mining occurs.</li><li data-v-80126aae>Some pools require KYC or reject unauthorized connections. These are excluded from measurements when unavailable.</li><li data-v-80126aae>Block miner attribution is looked up from mempool.space after the race completes and is provided for informational context only.</li></ul></section><section class="about-section" data-v-80126aae><h2 data-v-80126aae>For Pool Operators</h2><p data-v-80126aae> If you would like your pool added to StratumRace, please open an issue on our <a href="https://github.com/proofofmike/stratum-race/issues" target="_blank" rel="noopener" data-v-80126aae>GitHub repository</a>. Pools should have an established user base with a cumulative BTC hashrate of approximately 1+ PH/s to be considered for inclusion. </p><p data-v-80126aae> If you are a pool operator and would like your pool removed, open an issue and we will take action. The StratumRace operators reserve the right to add and remove pools from the site at their discretion. </p></section><section class="about-section" data-v-80126aae><h2 data-v-80126aae>Feedback &amp; Issues</h2><p data-v-80126aae> Found a bug, have a question, or want to request a feature? Open an issue on our <a href="https://github.com/proofofmike/stratum-race/issues" target="_blank" rel="noopener" data-v-80126aae>GitHub repository</a>. </p></section><section class="about-section" data-v-80126aae><h2 data-v-80126aae>Project &amp; Contributors</h2><p data-v-80126aae> StratumRace began as an original concept and Python CLI measurement tool created by <a href="https://proofofmike.com" target="_blank" rel="noopener" data-v-80126aae>ProofOfMike</a>. </p><p data-v-80126aae><a href="https://x.com/OGBTC" target="_blank" rel="noopener" data-v-80126aae>Marshall Long</a> helped bring the project to the web by creating the first browser-based implementation and contributing to its early development. </p><p data-v-80126aae> The current platform was redesigned and rebuilt by <a href="https://proofofmike.com" target="_blank" rel="noopener" data-v-80126aae>Mike</a> and <a href="https://atlaspool.io" target="_blank" rel="noopener" data-v-80126aae>Matt</a>, expanding the original tool into the multi-vantage measurement and analytics platform available today. </p><p data-v-80126aae> Follow the maintainers of StratumRace on X: <a href="https://x.com/proofofmike" target="_blank" rel="noopener" data-v-80126aae>@proofofmike</a> and <a href="https://x.com/AtlasPool_io" target="_blank" rel="noopener" data-v-80126aae>@AtlasPool_io</a>. </p></section><section class="about-section" data-v-80126aae><h2 data-v-80126aae>Open Source</h2><p data-v-80126aae> StratumRace is open source. The measurement collector and standalone web application are available on <a href="https://github.com/proofofmike/stratum-race" target="_blank" rel="noopener" data-v-80126aae>GitHub</a>. Anyone can review the code, verify the methodology, contribute improvements, or run their own instance. </p></section></article>',1)])])}const d=e(i,[["render",r],["__scopeId","data-v-80126aae"]]);export{d as default};
